def get_country_disasters(country, limit=20):
    results = [d for d in HISTORICAL_DISASTERS if d.get("country") == country]
    results.sort(key=lambda x: x.get("date", ""), reverse=True)
    return results[:limit]

def get_disasters_by_type(disaster_type, limit=20):
    results = [d for d in HISTORICAL_DISASTERS if d.get("type") == disaster_type]
    results.sort(key=lambda x: x.get("date", ""), reverse=True)
    return results[:limit]

def get_country_research(country, limit=10):
    results = [r for r in RESEARCH_ARTICLES if country in r.get("countries", [])]
    results.sort(key=lambda x: x.get("year", 0), reverse=True)
    return results[:limit]

def get_research_by_type(disaster_type, limit=10):
    results = [r for r in RESEARCH_ARTICLES if disaster_type in r.get("types", [])]
    results.sort(key=lambda x: x.get("year", 0), reverse=True)
    return results[:limit]

def get_all_disaster_types():
    return sorted(set(d["type"] for d in HISTORICAL_DISASTERS))

def get_tropical_disasters(limit=30):
    tropical_countries = [
        "Bangladesh", "India", "Philippines", "Indonesia", "Thailand", "Vietnam",
        "Myanmar", "Sri Lanka", "Malaysia", "Nigeria", "Kenya", "Ethiopia",
        "Somalia", "DR Congo", "Madagascar", "Mozambique", "Tanzania", "Cameroon",
        "Ghana", "Senegal", "Ivory Coast", "Sierra Leone", "Uganda", "Niger", "Chad",
        "Brazil", "Colombia", "Peru", "Ecuador", "Guatemala", "Honduras", "Haiti",
        "Cuba", "Costa Rica", "Nicaragua", "Dominican Republic", "Panama", "Bolivia",
        "Fiji", "Tonga", "Vanuatu", "Papua New Guinea"
    ]
    results = [d for d in HISTORICAL_DISASTERS if d.get("country") in tropical_countries]
    results.sort(key=lambda x: x.get("date", ""), reverse=True)
    return results[:limit]
